import http from 'k6/http';
import { check, sleep } from 'k6';
import { SharedArray } from 'k6/data';
import { Rate } from 'k6/metrics';

const errorRate = new Rate('errors');
const users = new SharedArray('users', function() {
  return JSON.parse(open('./testdata/users.json'));
});

export const options = {
  scenarios: {
    warmup: {
      executor: 'constant-vus', vus: 10, duration: '30s',
      gracefulStop: '0s', tags: { phase: 'warmup' },
    },
    load_test: {
      executor: 'ramping-vus', startTime: '30s',
      stages: [
        { duration: '1m', target: 50 },
        { duration: '3m', target: 50 },
        { duration: '30s', target: 0 },
      ],
      tags: { phase: 'test' },
    },
  },
  thresholds: {
    'http_req_duration{phase:test}': ['p(99)<200', 'p(50)<50'],
    'http_req_failed{phase:test}': ['rate<0.001'],
    'errors{phase:test}': ['rate<0.01'],
  },
};

export default function() {
  const user = users[Math.floor(Math.random() * users.length)];
  const res = http.get(`http://api.example.com/users/${user.id}`);
  check(res, { 'status is 200': r => r.status === 200 }) || errorRate.add(1);
  sleep(Math.random() * 3 + 1);
}
